"use client";

import { useEffect, useState } from "react";
import { Button } from "@/app/ui/button";
import { PaperAirplaneIcon, XMarkIcon } from "@heroicons/react/24/outline";
import { MessageFeature } from "@prisma/client";
//we didn't export from there, how are we importing? because it's a type generated by prisma based on our database schema, and it's available globally in our project. When we run prisma generate, it creates TypeScript types for our database models, and we can import those types directly from the generated Prisma client. In this case, MessageFeature is likely an enum or type defined in our Prisma schema, and
// we can use it in our TypeScript code by importing it from "@prisma/client". that's where it's exported from, even though we didn't explicitly export it ourselves.
import {
  sendChatMessageWithFeatures,
  updateChatViewedContribSummarySha,
} from "@/app/lib/actions";
import {
  fetchCurrentGithubSha,
  generateAndStoreRepoSummary,
  generateAndStoreAllContribSummaries,
  updateChatViewedSha,
  updateContribViewedSha,
} from "@/app/lib/actions";
import { ZodNullable } from "zod";
//ZodNullable is a utility type from the Zod library that represents a value that can either be of a specified type or null. It's often used in TypeScript to indicate that a variable can hold a value of a certain type or be null, providing better type safety and clarity in the code. In this context, it's being used to indicate that the chatLastViewedContribSummarySha can either be a string (representing the SHA) or null (indicating that it hasn't been viewed yet).
//TODO : where else can this be used? if needed elsewhere, we can use it for consistency.

// TODO : make questions for repo n contributor separate.
//TODO : move types to definitions.ts
type RepoAction = MessageFeature;

type ChatMessage = {
  role: "user" | "assistant";
  content: string;
  features?: RepoAction[];
};
// ? means optional, so features may or may not be present on a ChatMessage. This allows us to have messages that don't necessarily have associated features, while still maintaining type safety when we do have features. When we access msg.features, we should always check if it exists before trying to use it, since it's not guaranteed to be there on every message. 

const REPO_ACTIONS: Array<{ id: RepoAction; label: string }> = [
  { id: "generate_questions", label: "Evaluation Questions" },
  { id: "repo_chat", label: "Ask more about Repository" },
];
// TODO : is a better way to manage the actions and their labels? we can also consider using a Map for better performance if we have a large number of actions, but for a small fixed set of actions, an array is simple and easy to manage. Additionally, if we want to make the actions dynamic in the future, we might want to fetch them from the server or define them in a separate configuration file, but for now, this approach is straightforward and works well for our use case.

export default function ChatSection({
  repoId,
  chatId,
  userId,
  githubUrl,
  repoName,
  initialMessages = [],
  repoOwner,
  repoLastCommitSha,
  repoLastSummarySha,
  repoStoredSummary,
  chatLastViewedSummarySha,
  chatLastViewedContribSummarySha = ZodNullable,
  chatLastChatSha, 
  contributors = [], //can't be empty, because someone has to make the repo atleast. but we should do error handling wherever we're sending props from it there's no contributors.
  //TODO : remove unused values if not needed
}: {
  repoId?: string;
  chatId?: string;
  userId: string;
  githubUrl?: string; //means may or may not have a github url?
  repoName?: string;
  initialMessages?: ChatMessage[];
  repoOwner?: string;
  repoLastCommitSha?: string | null;
  repoLastSummarySha?: string | null;
  repoStoredSummary?: string | null;
  chatLastViewedSummarySha?: string | null;
  // contributorId → viewedSha for each contributor the user has viewed
  chatLastViewedContribSummarySha?: string | null;
  chatLastChatSha?: string | null;
  contributors?: {
    id: string;
    githubLogin: string;
    summary?: string | null;
    lastSummarySha?: string | null;
  }[]; //why send summary already? evaluator is likely to view them.
}) {
  // 'chat' = normal chat view; 'summary' = summary panel
  type ViewMode = "chat" | "summary";

  //TODO : all following use states etc should set defaut values from props or wherever, so page is already rendered with correct data and no need to wait for use effect to update states, which can cause unwanted loading states and bad user experience. for example, repo summary text should be set from repoStoredSummary prop, so when user opens summary panel, they can see the stored summary immediately without waiting for it to be fetched or generated again. same for contributor summaries, we can initialize the state with the summaries passed in props, so they're displayed right away when user opens the summary panel. this way we can ensure a smoother and faster user experience, as the relevant information is already available and displayed without unnecessary delays.
  const [viewMode, setViewMode] = useState<ViewMode>("chat");

  // The live SHA fetched from GitHub when summary panel opens. Where are we fetching it from? 
  const [liveGithubSha, setLiveGithubSha] = useState<string | null>(null);

  // Summary text states — start from stored values so no re-fetch on first open (say user opens summary and in repo table summary is stale, show option to regenerate newest, but if earlier user saw summary, and it's since been updated in repo table say because some other user requested summary to be regenerated after latest commits, show the newest summary in repo table, and just display message saying there have been changes since user last saw the summary.)
  const [repoSummaryText, setRepoSummaryText] = useState<string | null>(
    repoStoredSummary ?? null,
  );

  const [contribSummaries, setContribSummaries] = useState<
    Record<string, string>
  >(
    Object.fromEntries(
      contributors
        .filter((c) => c.summary)
        .map((c) => [c.githubLogin, c.summary!]),
    ),
  );

  const [summaryLoading, setSummaryLoading] = useState<string | null>(null);
  // value = 'repo' | contributor login | null

  const [messages, setMessages] = useState<ChatMessage[]>(initialMessages);
  //the type of input is defined outside () why? why not inside use state() along with []?
  // useState(<Array<{ role: string; content: string }>>[]) like this?
  // because we want to explicitly define the type of the state variable, and
  // it can be more readable to separate the type definition from the initial value.
  // but it's also common to define the type inline with the initial value, so it's mostly a matter of style and preference.
  // both ways are valid and will work correctly in TypeScript.

  const [input, setInput] = useState("");
  const [sending, setSending] = useState(false);
  const [selectedActions, setSelectedActions] = useState<RepoAction[]>([]);
  const [sendError, setSendError] = useState<string | null>(null);

  const isRepoLoaded = !!repoId && !!chatId; //if there's no repoId and chatId,
  // it means the repo is not loaded yet, another ! means they're loaded
  // so we can show the action buttons
  // now that we navigate to chat section only after repo is loaded, is the check needed?
  //yes, say user opens /chat endpoint directly without loading any repo, we should show them
  // TODO : the message/button to put repo url first, instead of showing empty chat section. or redirect to dashboard endpoint. that's better. less clicks for user

  // Is the repo summary stale compared to live GitHub?
  const repoSummaryIsStale =
    liveGithubSha !== null && liveGithubSha !== repoLastSummarySha;

  // Did user last view the repo summary at an older SHA?
  const repoUpdatedSinceViewed =
    repoLastSummarySha !== null &&
    chatLastViewedSummarySha !== repoLastSummarySha;

  // Per-contributor: did the contributor's summary change since user last viewed it?
// TODO : all contributors should have same last summary sha, because when we update, we update all of them together, so we should store just one sha for all contributors instead of per contributor, which can simplify the logic and reduce the chances of inconsistency. we can just store the latest sha among all contributors, and compare it with chatLastViewedContribSummarySha to determine if any contributor summary has been updated since user last viewed. this way we don't need to check each contributor individually, and we can ensure that if any contributor summary is updated, the user will be notified when they view the summaries again.
  // contributor.lastSummarySha is what was generated last;
  // chatContribViewedShas[contributor.id] is what the user last saw.
  const latestContribSummarySha =
    contributors.find((c) => c.lastSummarySha)?.lastSummarySha ?? null;

  const contribSummariesUpdatedSinceViewed =
    latestContribSummarySha !== null &&
    chatLastViewedContribSummarySha !== latestContribSummarySha;

  // Is chat history using an older repo version?
  const chatIsStale =
    liveGithubSha !== null &&
    chatLastChatSha !== null &&
    chatLastChatSha !== liveGithubSha;

  // keep UI in sync when user opens a different chat from sidebar
  useEffect(() => {
    setMessages(initialMessages);
  }, [chatId, initialMessages]);

  useEffect(() => {
    if (viewMode !== "summary" || !repoOwner || !repoName) return;

    // TODO : we should just get it in props, no need to keep checking on each effect run while user is using chat for current session, only get at start of session through props from parent, and if updated keep updated value.
    // Fetch live GitHub SHA once on open
    void fetchCurrentGithubSha(repoOwner, repoName)
      .then(setLiveGithubSha)
      .catch((error) => {
        const message =
          error instanceof Error
            ? error.message
            : "Unable to fetch latest GitHub changes.";
        setSendError(message);
      });

    // Record that user has viewed the repo summary at the current stored SHA, 
    // TODO : check if it updated only if it is different from stored one
    if (chatId && repoLastSummarySha) {
      void updateChatViewedSha(chatId, repoLastSummarySha).catch(() => {});
    }

    // Record per-contributor: for each contributor that has a generated summary,
    // upsert their entry in ChatContributorViewedSha
    // TODO : just one entry for all contributors as mentioned above, so we can just update that one entry with latestContribSummarySha if it's different from chatLastViewedContribSummarySha, and we can do that regardless of whether user views summary or chat, because it just indicates the latest summary sha that user has seen, and if it's different from latestContribSummarySha, it means there's an update that user hasn't seen yet.
    if (chatId && latestContribSummarySha) {
      void updateChatViewedContribSummarySha(
        chatId,
        latestContribSummarySha,
      ).catch(() => {});
    }
  }, [
    viewMode,
    repoOwner,
    repoName,
    chatId,
    repoLastSummarySha,
    latestContribSummarySha,
  ]);
  //  TODO : why combine all changes in one use effect? we can separate them into multiple use effects based on their dependencies, for example, fetching live GitHub SHA can be in a separate use effect that only depends on repoOwner and repoName, while updating viewed SHAs can be in another use effect that depends on chatId and the respective SHAs. this way we can have more granular control over when each effect runs, and it can also improve readability by separating different concerns into different effects. however, since both actions are related to viewing the summary and they both need to run when the user opens the summary panel, it can also make sense to keep them together in one effect for simplicity. it's a trade-off between separation of concerns and simplicity, and in this case, keeping them together is reasonable since they're closely related actions that both pertain to the summary view.

  function handleSelectAction(id: RepoAction) {
    setSelectedActions((prev) =>
      prev.includes(id) ? prev.filter((item) => item !== id) : [...prev, id],
    );
  }

  function getActionLabel(id: RepoAction) {
    return REPO_ACTIONS.find((action) => action.id === id)?.label ?? id;
  } // actions are fixed, why do we use function on client? why not do ssr of actions and pass label directly? because we want to keep the client component simple and not rely on server-side rendering for dynamic data. By defining the actions and their labels in the client component, we can easily manage the state and interactions without needing to fetch or compute anything from the server. This also allows for a more responsive user experience, as the action labels are readily available without any additional server requests. Additionally, if we ever want to make the actions dynamic in the future, having this logic on the client side will make it easier to implement those changes without needing to modify server-side code.

  function buildUserMessage(text: string, actions: RepoAction[]) {
    const actionLabel = actions.map(getActionLabel).join(", ");
    return text ? `[${actionLabel}] ${text}` : `[${actionLabel}]`;
  }

  async function handleGenerateRepoSummary() {
    if (!repoId || !liveGithubSha) return;
    setSummaryLoading("repo");
    try {
      const text = await generateAndStoreRepoSummary(repoId, liveGithubSha);
      // TODO : also need to update chat table sha right? for last viewed summary
      setRepoSummaryText(text);
    } finally {
      setSummaryLoading(null);
    }
  }
  // TODO : why not also use catch block to set error if summary generation fails? we should handle errors gracefully and inform the user if something goes wrong during summary generation. we can add a catch block to handle any errors that may occur during the API call, and set an appropriate error message in the state to display to the user. this way, if the summary generation fails for any reason (e.g., network issues, server errors), the user will be informed and can take appropriate action (e.g., try again later).

  async function handleGenerateAllContribSummaries() {
    if (!repoId || !liveGithubSha || !chatId) return;
    setSummaryLoading("contributors");
    try {
      const all = await generateAndStoreAllContribSummaries(
        repoId,
        liveGithubSha,
      );
      setContribSummaries((prev) => ({ ...prev, ...all }));
      await updateChatViewedContribSummarySha(chatId, liveGithubSha);
    } finally {
      setSummaryLoading(null);
    }
  }
  // TODO : same for error handling here as well, we should add error handling to this function as well to ensure that if there's an issue during the generation of contributor summaries, the user is informed appropriately. We can add a catch block to handle any errors that may occur during the API call, and set an error message in the state to display to the user. This way, if the generation of contributor summaries fails for any reason, the user will be aware of the issue and can take appropriate action (e.g., try again later).

  async function handleSend() {
    if (!isRepoLoaded || sending) return;

    const userText = input.trim().toLowerCase();
    const selected = selectedActions.length
      ? selectedActions
      : (["repo_chat"] as RepoAction[]);

    if (
      !userText &&
      selectedActions.length === 1 &&
      selected[0] === "repo_chat"
    )
      return;

    setSending(true);
    setSendError(null);
    setInput("");

    const userMessage = buildUserMessage(userText, selected);
    setMessages((prev) => [
      ...prev,
      { role: "user", content: userMessage, features: selected },
    ]);

    // here we will need to add final features decided.

    try {
      const answer = await sendChatMessageWithFeatures({
        chatId: chatId!,
        repoId: repoId!,
        userText,
        selectedFeatures: selected,
      });
      setMessages((prev) => [...prev, { role: "assistant", content: answer }]);
    } catch (error) {
      const message =
        error instanceof Error
          ? error.message
          : "Request failed. Please try again.";
      setSendError(message);
    } finally {
      setSending(false); // TODO : set sending can be used for showing loading state on UI, like disabling buttons and input, and showing spinner if needed.
      // TODO : how to stream answer being generated? we can use web socket or server sent events for that, but it will require more complex implementation both on client and server side. for now we can just show the final answer after it's generated, and maybe add a loading spinner while waiting for the response.
      setSelectedActions([]);
    }
  }

  const isDisabled = !isRepoLoaded;
  const effectiveActions =
    selectedActions.length > 0 ? selectedActions : ["repo_chat"];
  const isRepoChatOnly =
    effectiveActions.length === 1 && effectiveActions[0] === "repo_chat";
  const isSendDisabled =
    isDisabled || sending || (!input.trim() && isRepoChatOnly);

  return (
    <>
    {/* TODO : create separate components for chat messages and summary if needed for clarity. */}
      {/* Heading row — lives outside the chat card */}
      <div className="mb-4 flex items-center gap-3">
        <h1 className="text-xl font-semibold md:text-2xl">
          {viewMode === "summary"
            ? `${repoName ?? "Repository"} Summary`
            : `Chat with ${repoName ?? "Repository"}`}
        </h1>
        {isRepoLoaded &&
          (viewMode === "chat" ? (
            <button
              onClick={() => setViewMode("summary")}
              className="rounded-full border border-gray-300 bg-white px-3 py-1 text-xs font-medium text-gray-600 hover:border-blue-400 hover:text-blue-600 transition-colors"
            >
              {repoSummaryIsStale || !repoLastSummarySha
                ? "Generate Summary"
                : "View Summary"}
            </button>
          ) : (
            <button
              onClick={() => setViewMode("chat")}
              className="rounded-full border border-gray-300 bg-white px-3 py-1 text-xs font-medium text-gray-600 hover:border-blue-400 hover:text-blue-600 transition-colors"
            >
              Chat with Repo
            </button>
          ))}
      </div>
      <div className="flex h-[calc(100vh-4rem)] min-h-0 flex-col overflow-hidden rounded-lg border border-gray-200 bg-white shadow-sm">
        {viewMode === "summary" ? (
          /* ── Summary panel ──────────────────────────────────────── */
          <div className="flex-1 min-h-0 overflow-y-auto p-4 space-y-6">
            {/* Staleness note for repo summary */}
            {repoUpdatedSinceViewed && (
              <p className="text-xs text-amber-600 bg-amber-50 border border-amber-200 rounded px-3 py-1">
                ⚠ The repository has been updated since you last viewed this
                summary.
              </p>
            )}

{/* TODO : when one generate button is clicked disable other one in summaries tab. also show the buttons side by side, whichever is clicked gets displaye, and don't always show regenerate availavle, when the summary is already in repo table and is up to dat ewith latest commit on github repo, show only view summary and then fetch from repo and show summary like that. don't regenerate. same with contributor's summary. 
also don't always show notification of update, only show when summaries are actually from a newer commit sha than when user last saw them. and show regenerate instead of view if even repo table doesn't have summary up to date with the latest commit sha on repo in github. otherwise show view summary if repo summary is up to date with latest commit sha on github repo. and in the chat, show notification in between messages say after user last chatted, next time user opens the chat the latest commit on github repo is checked, and put the notification like there's date in whatsapp between messages. for current session i.e a continuous chat don't keep checking if there's been new commits. also get last chat sha or summary sha in chat etc etc and check actually if they've changed and only then show the notification of change. not all the time. do not show generate if latest summaries are already in db, check sha of repo on github and in contribuotr n repo tables that store summaries and their shas. if already up to date, button should say view, if not up to date show regenerate, and if some other user regenerated newer summary and some other user had seen an older summary, then when they open the chat they should be shown newer summary from db only but with notification that the summary has been updated, using the chat shas for summaries.*/}
            {/* Repo Summary button + output */}
            <div className="space-y-2">
              <button
                onClick={handleGenerateRepoSummary}
                disabled={summaryLoading === "repo" || !liveGithubSha}
                className="rounded-full border px-3 py-1 text-xs font-medium bg-blue-50 border-blue-400 text-blue-700 disabled:opacity-40 transition-colors"
              >
                {summaryLoading === "repo"
                  ? "Generating..."
                  : repoSummaryIsStale
                    ? "Regenerate Repo Summary"
                    : repoSummaryText
                      ? "Regenerate Repo Summary"
                      : "Generate Repo Summary"}
              </button>
              {repoSummaryText && (
                /* Displayed exactly like an assistant message bubble */
                <div className="flex justify-start">
                  <div className="max-w-[80%] rounded-lg px-4 py-2 bg-gray-100 text-gray-900">
                    <p className="text-xs font-medium text-gray-500 mb-1">
                      Repository Summary
                    </p>
                    <p className="text-sm whitespace-pre-wrap">
                      {repoSummaryText}
                    </p>
                  </div>
                </div>
              )}
            </div>

            {/* Contributor Summaries button + per-contributor output */}
            <div className="space-y-2">
              <p className="text-xs font-medium text-gray-500 uppercase tracking-wide">
                Contributor Summaries
              </p>

              {contribSummariesUpdatedSinceViewed && (
                <p className="text-xs text-amber-600 bg-amber-50 border border-amber-200 rounded px-3 py-1">
                  ⚠ Contributor summaries were updated since your last view.
                </p>
              )}

              <button
                onClick={handleGenerateAllContribSummaries}
                disabled={summaryLoading === "contributors" || !liveGithubSha}
                className="rounded-full border px-3 py-1 text-xs font-medium bg-blue-50 border-blue-400 text-blue-700 disabled:opacity-40 transition-colors"
              >
                {summaryLoading === "contributors"
                  ? "Generating..."
                  : contributors.length === 0
                    ? "No contributors"
                    : "Generate Contributor Summaries"}
              </button>

              {contributors.length === 0 ? (
                <p className="text-sm text-gray-400">No contributors found.</p>
              ) : (
                contributors.map((c) => {
                  const contribText = contribSummaries[c.githubLogin];
                  if (!contribText) return null;

                  return (
                    <div key={c.githubLogin} className="flex justify-start">
                      <div className="max-w-[80%] rounded-lg px-4 py-2 bg-gray-100 text-gray-900">
                        <p className="text-xs font-medium text-gray-500 mb-1">
                          @{c.githubLogin}
                        </p>
                        <p className="text-sm whitespace-pre-wrap">
                          {contribText}
                        </p>
                      </div>
                    </div>
                  );
                })
              )}
            </div>
          </div>
        ) : (
          /* ── Chat panel (existing UI, unchanged) ──────────────────── */
          <>
            {/* Staleness note when returning to chat */}
            {chatIsStale && (
              <div className="px-4 pt-3">
                <p className="text-xs text-amber-600 bg-amber-50 border border-amber-200 rounded px-3 py-1">
                  ⚠ The repository has been updated since your last message.
                  Replies will use the latest ingested version.
                </p>
              </div>
            )}
            {sendError && (
              <div className="px-4 pt-3">
                <p className="text-xs text-red-700 bg-red-50 border border-red-200 rounded px-3 py-1">
                  {sendError}
                </p>
              </div>
            )}
            {/* TODO : don't show user load repo? */}
            {/* Messages */}
            <div
              className="flex-1 min-h-0 space-y-4 overflow-y-auto p-4"
              style={{ minHeight: "300px", maxHeight: "500px" }}
            >
              {messages.length === 0 && (
                <p className="text-center text-sm text-gray-400">
                  {isRepoLoaded
                    ? "No messages yet. Start a conversation!"
                    : "Your chat will appear here once you load a repository."}
                  {/* TODO : load a repo? check when that shows*/}
                </p>
              )}
              {messages.map((msg, idx) => {
                const labels =
                  msg.role === "user"
                    ? (msg.features ?? []).map(getActionLabel)
                    : [];
                const hasContent = !!msg.content?.trim();

                return (
                  // map has element, index arguments
                  <div
                    key={idx}
                    className={`flex ${msg.role === "user" ? "justify-end" : "justify-start"}`}
                  >
                    <div
                      className={`max-w-[80%] rounded-lg px-4 py-2 ${
                        msg.role === "user"
                          ? "bg-blue-500 text-white"
                          : "bg-gray-100 text-gray-900"
                      }`}
                    >
                      {labels.length > 0 && (
                        <div className="mb-2 flex flex-wrap gap-1">
                          {labels.map((label) => (
                            <span
                              key={label}
                              className={
                                msg.role === "user"
                                  ? "rounded-full bg-blue-600 px-2 py-0.5 test-[10px] font-medium text-white"
                                  : "rounded-full bg-gray-200 px-2 py-0.5 test-[10px] font-medium text-white"
                              }
                            >
                              {label}
                            </span>
                          ))}
                        </div>
                      )}
                      {/* TODO : move action request to above actions, and user text keep here but with larger font */}
                      {hasContent ? (
                        <p className="text-sm whitespace-pre-wrap">
                          {msg.content}
                        </p>
                      ) : (
                        labels.length > 0 && (
                          <p className="text-sm opacity-80">Action Request</p>
                        )
                      )}{" "}
                    </div>
                  </div>
                );
              })}
            </div>

            {/* Input */}
            <div className="border-t border-gray-200 p-4 pt-3 pb-1">
              <p className="mb-2 text-xs font-medium text-gray-500 uppercase tracking-wide">
                Repository Actions
              </p>
              <div className="flex flex-wrap gap-2">
                {REPO_ACTIONS.map((action) => (
                  <button
                    key={action.id}
                    onClick={() => handleSelectAction(action.id)}
                    disabled={isDisabled || sending}
                    className={`rounded-full border px-3 py-1 text-xs font-medium transition-colors
            ${
              selectedActions.includes(action.id)
                ? "border-blue-500 bg-blue-100 text-blue-700"
                : "border-gray-300 bg-white text-gray-600 hover:border-blue-400 hover:text-blue-600"
            }
            disabled:cursor-not-allowed disabled:opacity-40`}
                  >
                    {action.label}
                  </button>
                ))}
              </div>
              <div className="px-4 pb-4 pt-2">
                {selectedActions.length > 0 && (
                  <div className="mb-2 flex items-center gap-1">
                    {selectedActions.map((id) => (
                      <span
                        key={id}
                        className="inline-flex items-center gap-1 rounded-full bg-blue-500 px-3 py-1 text-xs font-medium text-white"
                      >
                        {REPO_ACTIONS.find((a) => a.id === id)?.label}
                        {/* TODO : why find? why not get action.label like above? */}
                        <button
                          onClick={() => handleSelectAction(id)}
                          className="m1-1 rounded-full hover:bg-blue-600 p-0.5"
                          aria-label="Remove selected action"
                        >
                          <XMarkIcon className="h-3 w-3" />
                        </button>
                      </span>
                    ))}
                  </div>
                )}
                <div className="flex gap-2">
                  <input
                    type="text"
                    value={input}
                    onChange={(e) => setInput(e.target.value)}
                    onKeyDown={(e) =>
                      e.key === "Enter" && !isSendDisabled && handleSend()
                    }
                    placeholder={
                      isDisabled
                        ? "Load a repository to start chatting..."
                        : selectedActions.includes("generate_questions")
                          ? 'Optional: focus area (e.g. "authentication flow")'
                          : "Ask a question..."
                    }
                    // chaining ternary operators for placeholder, is it good? is it better to have separate function to get placeholder based on selected actions? it's a bit complex but still readable, and keeps the JSX cleaner. if we put it in a separate function, we would need to pass selectedActions and isDisabled as arguments, which can make it less straightforward. so in this case, I think using chained ternary operators is acceptable for the placeholder text.
                    // TODO : load repo should be shown? or we can redirect to url enter page.
                    disabled={isDisabled || sending}
                    className="flex-1 rounded-md border border-gray-300 px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500 disabled:bg-gray-50 disabled:text-gray-400"
                  />
                  <Button onClick={handleSend} disabled={isSendDisabled}>
                    <PaperAirplaneIcon className="h-5 w-5" />
                  </Button>
                </div>
              </div>
            </div>
          </>
        )}
      </div>
    </>
  );
}
